/** Account default from GET /forms/init-data — code + name JOIN BE (`form-init-data.md`). */

export interface AccountDefault {
  code: string;
  name: string;
}

export interface AccountDefaultDto {
  code?: string;
  name?: string;
}

export function mapAccountDefault(dto?: AccountDefaultDto | null): AccountDefault | null {
  const code = dto?.code?.trim();
  if (!code) return null;
  return { code, name: dto?.name?.trim() ?? '' };
}

/** Apply init-data default on create when field still empty — parity `defaultProcessingLevel`. */
export function applyVoucherAccountDefault(
  isNew: boolean,
  currentCode: string | undefined,
  defaultAccount: AccountDefault | null | undefined,
  setCode: (code: string) => void,
  setName: (name: string) => void,
): void {
  if (!isNew || currentCode?.trim() || !defaultAccount?.code) return;
  setCode(defaultAccount.code);
  setName(defaultAccount.name);
}
